/* ═══════════════════════════════════════════════════════════════
   App.tsx – CloudMon Application Shell
   Provides routing, shared header, and project context.
   ═══════════════════════════════════════════════════════════════ */
import React, { useEffect, useRef, useState } from 'react';
import { Link, Navigate, Route, Routes, useLocation, useNavigate } from 'react-router-dom';

// @ts-ignore
import './App.css';

import { ProjectsProvider, useProjects } from './context/ProjectsContext';
import LandingPage from './pages/LandingPage';
import ProjectEditorPage from './pages/ProjectEditorPage';
import ProjectsPage from './pages/ProjectsPage';
import catalog, { PALETTE_SECTIONS } from './data/componentCatalog';

/* ── Header ──────────────────────────────────────────────────── */
function AppHeader() {
  const navigate = useNavigate();
  const location = useLocation();
  const { createNewProject } = useProjects();

  function handleNewProject() {
    const project = createNewProject();
    navigate(`/projects/${project.id}`);
  }

  const [activeTab, setActiveTab]     = useState<string>(PALETTE_SECTIONS[0].title);
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  /* Close on outside click */
  useEffect(() => {
    function onOutside(e: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target as Node)) {
        setDropdownOpen(false);
      }
    }
    document.addEventListener('mousedown', onOutside);
    return () => document.removeEventListener('mousedown', onOutside);
  }, []);

  /* Close on navigation */
  useEffect(() => { setDropdownOpen(false); }, [location.pathname]);

  const activeSection = PALETTE_SECTIONS.find((s) => s.title === activeTab) ?? null;

  function handleDragStart(key: string, e: React.DragEvent) {
    e.dataTransfer.setData('componentType', key);
    e.dataTransfer.effectAllowed = 'copy';
    setDropdownOpen(false);
  }

  const isLanding  = location.pathname === '/';
  const isProjects = location.pathname === '/projects' || location.pathname === '/projects/';
  const isEditor   = /^\/projects\/[^/]+/.test(location.pathname);

  return (
    <header className="app-header">
      <div className="logo">
        <Link to="/" className="logo-link">CloudMon</Link>
      </div>

      {/* ── Component picker dropdown – editor pages only ── */}
      {isEditor && (
        <div className="comp-dropdown" ref={dropdownRef}>
          <button
            className={`comp-dropdown-trigger${dropdownOpen ? ' open' : ''}`}
            onClick={() => setDropdownOpen((o) => !o)}
          >
            <span>{activeTab}</span>
            <span className="comp-caret">{dropdownOpen ? '▴' : '▾'}</span>
          </button>

          {dropdownOpen && (
            <div className="comp-dropdown-panel">
              <div className="comp-tabs">
                {PALETTE_SECTIONS.map((s) => (
                  <button
                    key={s.title}
                    className={`comp-tab${activeTab === s.title ? ' active' : ''}`}
                    onClick={() => setActiveTab(s.title)}
                  >
                    {s.title}
                  </button>
                ))}
              </div>
              <div className="comp-items">
                {activeSection?.keys.map((key) => {
                  const spec = catalog[key];
                  if (!spec) return null;
                  return (
                    <div
                      key={key}
                      className="comp-item"
                      draggable
                      onDragStart={(e) => handleDragStart(key, e)}
                      title={spec.description}
                    >
                      <span
                        className="comp-item-icon"
                        style={{ background: spec.color, color: spec.textColor }}
                      >
                        {spec.icon}
                      </span>
                      <span className="comp-item-label">{spec.label}</span>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      )}

      <nav className="app-nav">
        <Link className={`nav-link${isLanding  ? ' active' : ''}`} to="/">Home</Link>
        <Link className={`nav-link${isProjects ? ' active' : ''}`} to="/projects">Projects</Link>
      </nav>

      <div className="header-actions">
        <button className="btn-primary" onClick={handleNewProject}>+ New Project</button>
      </div>
    </header>
  );
}

/* ── Root App ─────────────────────────────────────────────────── */
function App() {
  return (
    <ProjectsProvider>
      <div className="App">
        <AppHeader />
        <main className="app-main">
          <Routes>
            <Route path="/" element={<LandingPage />} />
            <Route path="/projects" element={<ProjectsPage />} />
            <Route path="/projects/:projectId" element={<ProjectEditorPage />} />
            <Route
              path="/projects/:projectId/requests/:requestId"
              element={<ProjectEditorPage />}
            />
            {/* Fallback */}
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
      </div>
    </ProjectsProvider>
  );
}

export default App;
